BEGIN { 
    print "📦 Root Directory:"
    print ""
}
{
    depth = gsub(/\//, "/", $0)
    if (depth == 1) {
        current_folder = $0
        sub(/\/.*/, "", current_folder)
        if (current_folder != prev_folder) {
            if (prev_folder != "") print ""
            print "📁 " current_folder "/"
            prev_folder = current_folder
        }
        indent = "   ├─ "
        sub(/^[^\/]*\//, "", $0)
        print indent $0
    }
}
END {
    print ""
    print "════════════════════════════════════════════════════════════"
}
'

